/** Capture a source into the Trace tab. Two lanes: Web (Firecrawl screenshot + extract) and SEC
 *  (EDGAR data API — authoritative facts by ticker/concept). The persisted record joins the list. */
function CaptureForm({ roomId, onCapture, onSec }: {
  roomId: string;
  onCapture: (roomId: string, url: string, goal: string) => Promise<{ ok: boolean; error?: string }>;
  onSec: (roomId: string, company: string, concept: string) => Promise<{ ok: boolean; error?: string }>;
}) {
  const [mode, setMode] = useState<"web" | "sec">("web");
  const [url, setUrl] = useState("");
  const [goal, setGoal] = useState("");
  const [company, setCompany] = useState("");
  const [concept, setConcept] = useState("");
  const [busy, setBusy] = useState(false);
  const [err, setErr] = useState<string | null>(null);
  const submit = async (e: FormEvent) => {
    e.preventDefault();
    if (busy) return;
    const ready = mode === "web" ? url.trim() : company.trim();
    if (!ready) { setErr("enter a " + (mode === "web" ? "URL" : "ticker")); return; }
    setBusy(true); setErr(null);
    try {
      const r = mode === "web"
        ? await onCapture(roomId, url.trim(), goal.trim() || "extract the key figures")
        : await onSec(roomId, company.trim(), concept.trim() || "revenue");
      if (!r.ok) setErr(r.error ?? "failed");
      else { setUrl(""); setGoal(""); setCompany(""); setConcept(""); }
    } catch (e2) {
      setErr(e2 instanceof Error ? e2.message : String(e2));
    } finally {
      setBusy(false);
    }

  label: string;
  detail?: string;
  status: TraceTone;
  /** Collapsible section (phase / spec / status) — keeps hundreds of steps navigable. */
  group?: string;
  /** When present, the step opens this cell on the work surface (split + pulse). */
  targetArtifactId?: string;
  targetElementId?: string;
  /** QA steps carry a captured screenshot (served from /public/qa-trace) + metrics. */
  screenshotUrl?: string;
  metrics?: { label: string; value: string }[];
  /** Pipeline-fed evidence: screenshots, logs, SSIM flicker diffs. */
  attachments?: TraceAttachment[];
}

/** Client-side cap on rendered steps (BOUND rule). Beyond this, paginate/lazy-load from the server. */
export const MAX_TRACE_STEPS = 500;

export interface TraceRecord {
  id: string;
  kind: "agent" | "qa";
  title: string;
  subtitle: string;
  ts: string;
  source: { tool: string; version?: string; env?: string; model?: string };
  verdict?: { label: string; tone: TraceTone };
  /** Honest provenance at the evidence level (NOT fabricated per-line code attribution). */
  attribution?: { ai: number; mixed: number; human: number };
  steps: TraceStep[];
  evidenceCards?: EvidenceCardArtifact[];
  raw: unknown;
}

/**
 * A REAL run of scripts/design-qa/floor.ts captured 2026-06-17 (P0=0 P1=0 P2=0 → SHIP).
 * The screenshots are the floor's actual output, copied to /public/qa-trace. Refresh by re-running
 * the floor and re-copying the PNGs; the metrics below are this run's real stdout.
 */
export const QA_TRACE_RECORD: TraceRecord = {
  id: "qa-design-floor",
  kind: "qa",
  title: "QA · NodeRoom design floor",
  subtitle: "Playwright visual + design-token sweep across 3 surfaces (scripts/design-qa/floor.ts)",

  onOpenSource: (artifactId: string, elementId?: string) => void;
}) {
  const phases = useMemo(() => {
    const seen: string[] = [];
    for (const s of record.steps) { const g = s.group ?? "Steps"; if (!seen.includes(g)) seen.push(g); }
    return seen;
  }, [record]);

  const { nodes, edges } = useMemo(() => {
    const COL = 248, ROW = 88;
    const rowOf: Record<string, number> = {};
    const nodes: Node[] = record.steps.map((s) => {
      const g = s.group ?? "Steps";
      const col = phases.indexOf(g);
      const row = (rowOf[g] = (rowOf[g] ?? -1) + 1);
      const label = s.label.length > 30 ? `${s.label.slice(0, 30)}…` : s.label;
      return {
        id: String(s.idx),
        position: { x: col * COL, y: row * ROW },
        data: { label: `${s.idx}. ${label}` },
        sourcePosition: Position.Right,
        targetPosition: Position.Left,
        style: {
          width: 200,
          fontSize: 11,
          fontWeight: 500,
          padding: "8px 10px",
          borderRadius: 10,
          border: `1px solid ${TONE[s.status]}`,
          background: "var(--bg-secondary)",
          color: "var(--text-primary)",
          textAlign: "left" as const,
        },
      };
    });
    const edges: Edge[] = [];
    for (let i = 0; i < record.steps.length - 1; i++) {
      edges.push({ id: `f${i}`, source: String(record.steps[i].idx), target: String(record.steps[i + 1].idx), animated: true, style: { stroke: "var(--line-strong)" } });
    }
    return { nodes, edges };
  }, [record, phases]);

  const [sel, setSel] = useState<TraceStep | null>(null);

